sql:
SELECT state_id, median_household_income
FROM socioeconomic_data
ORDER BY median_household_income DESC;

SELECT area
FROM area_statistics
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'Alaska');

SELECT AVG(life_expectancy) AS avg_life_expectancy
FROM socioeconomic_data
WHERE murder_rate > 10;

SELECT state_name
FROM states
ORDER BY population_density DESC;

SELECT SUM(frost_days) AS total_frost_days
FROM frost_data
WHERE state_id = 1;

SELECT state_name 
FROM states 
WHERE state_name = 'Alaska';
